"use client";

import { useTRPC } from '@/trpc/client';
import { useQuery } from '@tanstack/react-query';

const Todolist = () => {
  const trpc = useTRPC();
  const todolists = trpc.getTodos.queryOptions();
  return (
    <div>{JSON.stringify(todolists)}</div>
  )
}

export default Todolist